<template>
  <GuideLayout>
    <div class="ch-header">
      <span class="ch-header__num">第 2 章</span>
      <h1 class="ch-header__title">基础使用</h1>
      <p class="ch-header__desc">最小化运行示例、完整 Props / Emits 说明，以及可交互的三模式演示。</p>

      <p class="ch-text" style="margin-top: 10px;">
        安装依赖：<code>npm install @quick-code/x6-flow-designer</code><br>
        引入组件：<code>import { FlowDesignerLayout }  from '@quick-code/x6-flow-designer'</code>
      </p>
    </div>

    <!-- 2.1 最小化运行 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.1 最小化运行</h2>
      <p class="ch-text">只需将 <code>FlowDesignerLayout</code> 放入有明确宽高的父容器，指定 <code>mode</code> 即可：</p>
      <div class="ch-demo-frame" style="height: 380px">
        <CodePreviewer demo-name="demoSimple" />
      </div>
      <div class="ch-callout ch-callout--warning">
        ⚠️ <strong>注意</strong>：父容器必须有明确的宽高，画布会填满父容器空间。推荐 <code>height: 100vh</code> 或绝对定位布局。
      </div>
    </section>

    <!-- 2.3 Props 说明 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.2 Props 一览</h2>
      <div class="ch-table-wrap">
        <table class="ch-table">
          <thead><tr><th>Prop</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead>
          <tbody>
          <tr v-for="p in propsDoc" :key="p.name">
            <td><code>{{ p.name }}</code></td>
            <td><code class="ch-type">{{ p.type }}</code></td>
            <td>
              <a-button v-if="p.name == 'canvasConfig'" type="link" @click="showCode(defaultConfigRaw)">具体参考</a-button>
              <a-button v-else-if="p.name == 'permissionConfig'" type="link" @click="showCode(permissionConfigRaw)">具体参考</a-button>
              <code v-else>{{ p.default }}</code>
            </td>
            <td>{{ p.desc }} </td>
          </tr>
          </tbody>
        </table>
      </div>
    </section>

    <!-- 2.3 Emits 一览 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.3 Emits 一览</h2>
      <div class="ch-table-wrap">
        <table class="ch-table">
          <thead><tr><th>事件名</th><th>参数类型</th><th>说明</th></tr></thead>
          <tbody>
          <tr v-for="e in emitsDoc" :key="e.name">
            <td><code>{{ e.name }}</code></td>
            <td>
              <code class="ch-type">{{ e.arg }}</code>
              <RouterLink v-if="e.arg == 'FlowDesigner,Graph'" to="/guide/flowdesigner-api" class="ch-api-link">FlowDesigner参考</RouterLink>
              <a v-if="e.arg == 'FlowDesigner,Graph'" class="ch-api-link" href="https://x6.antv.antgroup.com/api/graph/graph" target="_blank">Graph参考</a>
            </td>
            <td v-html="e.desc"></td>
          </tr>
          </tbody>
        </table>
      </div>
    </section>

    <!-- 2.4 生命周期钩子一览 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.4 生命周期钩子一览</h2>
      <p class="ch-text">
        通过 Props 传递钩子函数，在关键操作节点触发回调。<code>before-*</code> 钩子返回 <code>false</code> 可阻止操作。
      </p>
      <div class="ch-table-wrap">
        <table class="ch-table">
          <thead><tr><th>钩子名称</th><th>参数类型</th><th>返回值</th><th>说明</th></tr></thead>
          <tbody>
          <tr v-for="h in lifecycleHooksDoc" :key="h.name">
            <td><code>{{ h.name }}</code></td>
            <td><code class="ch-type">{{ h.arg }}</code></td>
            <td><code class="ch-type">{{ h.return }}</code></td>
            <td>{{ h.desc }}</td>
          </tr>
          </tbody>
        </table>
      </div>
      <div class="ch-callout ch-callout--info">
        💡 <strong>提示</strong>：钩子函数通过 Props 传递（如 <code>:before-node-add="handleBeforeNodeAdd"</code>），
        而不是通过事件监听（<code>@before-node-add</code>）。Before 钩子返回 <code>false</code> 会阻止操作，返回 <code>true</code> 或 <code>undefined</code> 允许操作。
      </div>
    </section>

    <!-- 2.5 @ready 事件演示 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.5 @ready 事件演示</h2>
      <p class="ch-text">
        <code>@ready</code> 事件在画布初始化完成后触发，返回 <code>{ designer, graph }</code> 对象。
        <code>designer</code> 是 FlowDesigner 实例，提供画布管理、状态管理等高层 API；
        <code>graph</code> 是 X6 Graph 实例，可直接调用 X6 原生 API 进行底层操作。
      </p>

      <div class="ch-demo-frame">
        <CodePreviewer demo-name="demo-ready" />
      </div>

      <div class="ch-callout ch-callout--info">
        💡 <strong>提示</strong>：左侧日志面板实时显示事件触发过程。打开浏览器控制台，输入 <code>designer</code> 或 <code>graph</code> 可查看完整 API。
      </div>
    </section>

    <!-- 2.6 @mode-change 事件演示 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.6 @mode-change 事件演示</h2>
      <p class="ch-text">
        <code>@mode-change</code> 事件在模式切换时触发，返回新的模式名称。
        可用于响应模式变化，执行相应的 UI 更新或权限检查。
      </p>

      <div class="ch-demo-frame">
        <CodePreviewer demo-name="demo-mode-change" />
      </div>
    </section>

    <!-- 2.7 @selection-change 事件演示 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.7 @selection-change 事件演示</h2>
      <p class="ch-text">
        <code>@selection-change</code> 事件在选区变化时触发，返回当前选中的节点/连线数组。
        支持单选、多选、框选等多种选择方式。
      </p>

      <div class="ch-demo-frame">
        <CodePreviewer demo-name="demo-selection-change" />
      </div>
    </section>

    <!-- 2.8 节点生命周期钩子演示 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.8 节点生命周期钩子演示</h2>
      <p class="ch-text">
        节点生命周期包含 4 个钩子函数：
        <code>:before-node-add</code>、<code>:after-node-add</code>、
        <code>:before-node-remove</code>、<code>:after-node-remove</code>。
        <code>before-*</code> 钩子返回 <code>false</code> 可阻止操作。
      </p>

      <div class="ch-demo-frame">
        <CodePreviewer demo-name="demo-node-lifecycle" />
      </div>

      <div class="ch-callout ch-callout--warning">
        ⚠️ <strong>注意</strong>：取消"允许添加"或"允许删除"的勾选，相应操作将被 <code>before-*</code> 钩子拦截。
      </div>
    </section>

    <!-- 2.9 连线生命周期钩子演示 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.9 连线生命周期钩子演示</h2>
      <p class="ch-text">
        连线生命周期包含 4 个钩子函数：
        <code>:before-edge-add</code>、<code>:after-edge-add</code>、
        <code>:before-edge-remove</code>、<code>:after-edge-remove</code>。
        可用于连接验证、权限检查等场景。
      </p>

      <div class="ch-demo-frame">
        <CodePreviewer demo-name="demo-edge-lifecycle" />
      </div>

      <div class="ch-callout ch-callout--info">
        💡 <strong>提示</strong>：从一个节点的锚点拖拽到另一个节点的锚点来创建连线。选中连线后按 Delete 或 Backspace 删除。
      </div>
    </section>

    <!-- 2.10 数据加载钩子演示 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.10 数据加载钩子演示</h2>
      <p class="ch-text">
        <code>:after-data-loaded</code> 钩子在调用 <code>designer.load()</code> 完成后触发。
        可用于数据加载后的额外处理，如居中显示、缩放适配等。
      </p>

      <div class="ch-demo-frame">
        <CodePreviewer demo-name="demo-data-loaded" />
      </div>
    </section>

    <!-- 2.11 本章小结 -->
    <section class="ch-section">
      <h2 class="ch-section__title">2.11 本章小结</h2>
      <div class="ch-summary">
        <div class="ch-summary__item">✅ 父容器需设定宽高，画布自动填满</div>
        <div class="ch-summary__item">✅ <code>mode</code> 控制内置权限预设（design / readonly / preview）</div>
        <div class="ch-summary__item">✅ 通过 <code>@ready</code> 事件获取 FlowDesigner 实例进行编程式操作</div>
        <div class="ch-summary__item">✅ 下一章将详细讲解插槽系统</div>
      </div>
    </section>
    <!-- 只需要一个组件 -->
    <CodeDrawer ref="codeDrawerRef" />
  </GuideLayout>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import { RouterLink } from 'vue-router'
import GuideLayout from '../components/GuideLayout.vue'
import CodePreviewer from '../components/CodePreviewer.vue'
import demoReady from './examples/demo-ready.vue'

import CodeDrawer from '../components/CodeDrawer.vue'
import defaultConfigRaw from '@/components/FlowDesigner/core/defaultConfig.ts?raw'
import permissionConfigRaw from './examples/permissionConfig.json?raw'

const codeDrawerRef = ref()

function showCode(code) {
  // 直接调用 openDrawer 方法
  codeDrawerRef.value?.openDrawer({
    code: code,
    title: 'Vue 组件示例',
    width: 700, // 可选，默认 600
  })
}


const activeMode = ref<'design' | 'readonly' | 'preview'>('design')
const copyLabel = ref('复制')

const modes = [
  { value: 'design', label: '✏️ design' },
  { value: 'readonly', label: '👁 readonly' },
  { value: 'preview', label: '📺 preview' },
]

const modeDesc: Record<string, string> = {
  design: '设计模式：显示工具栏和节点面板，可拖拽节点、连线、编辑。',
  readonly: '只读模式：显示工具栏（无编辑按钮），不可操作节点，仅可查看和导出。',
  preview: '预览模式：隐藏所有 UI 面板，仅展示画布内容，适合最终展示场景。',
}

const demoNodes = [
  { shape: 'start-node', label: '🟢 开始' },
  { shape: 'approver-node', label: '✅ 审批' },
  { shape: 'end-node', label: '🔴 结束' },
]


function copy(text: string) {
  navigator.clipboard.writeText(text).then(() => {
    copyLabel.value = '已复制 ✓'
    setTimeout(() => { copyLabel.value = '复制' }, 2000)
  })
}

const propsDoc = [
  { name: 'mode', type: 'string', default: "'design'", desc: '初始模式，支持 design / readonly / preview 及自定义模式名' },
  { name: 'canvasConfig', type: 'Partial<CanvasConfig>', default: 'undefined', desc: '画布配置，与默认配置深度合并' },
  // { name: 'permissions', type: 'Partial<ModeCapabilities>', default: 'undefined', desc: '直接覆盖当前模式的权限（最高优先级）' },
  { name: 'permissionConfig', type: 'PermissionConfigMap', default: 'undefined', desc: '多模式权限配置映射表' },
  //{ name: 'getPermissions', type: '(mode) => ModeCapabilities', default: 'undefined', desc: '自定义权限解析函数，完全接管权限计算' },
  //{ name: 'shortcuts', type: 'ShortcutMap', default: 'undefined', desc: '自定义快捷键，与内置键位合并（同键位以自定义为准）' },
]

const emitsDoc = [
  // ─── 基础事件 ─────────────────────────────────────────────────────────
  { name: '@ready', arg: 'FlowDesigner,Graph', desc: '画布初始化完成， <br />返回 FlowDesigner 实例, <br />Graph实例参考(https://x6.antv.antgroup.com/api/graph/graph)' },
  // { name: '@save', arg: 'FlowData', desc: '用户触发保存时（Ctrl+S 或工具栏保存按钮）' },
  // { name: '@error', arg: 'Error', desc: '内部发生错误时' },
  { name: '@mode-change', arg: 'DesignerMode', desc: '模式切换时' },
  { name: '@selection-change', arg: 'Cell[]', desc: '选区变化时触发，返回当前选中的节点/连线数组' },
]

const lifecycleHooksDoc = [
  // ─── 节点生命周期钩子 ─────────────────────────────────────────────────────
  { name: ':before-node-add', arg: 'BeforeNodeAddEvent', return: 'boolean | Promise<boolean>', desc: '节点添加前钩子，返回 false 阻止添加' },
  { name: ':after-node-add', arg: 'AfterNodeAddEvent', return: 'void', desc: '节点添加后钩子' },
  { name: ':before-node-remove', arg: 'BeforeNodeRemoveEvent', return: 'boolean | Promise<boolean>', desc: '节点删除前钩子，返回 false 阻止删除' },
  { name: ':after-node-remove', arg: 'AfterNodeRemoveEvent', return: 'void', desc: '节点删除后钩子' },

  // ─── 连线生命周期钩子 ─────────────────────────────────────────────────────
  { name: ':before-edge-add', arg: 'BeforeEdgeAddEvent', return: 'boolean | Promise<boolean>', desc: '连线创建前钩子，返回 false 阻止连接' },
  { name: ':after-edge-add', arg: 'AfterEdgeAddEvent', return: 'void', desc: '连线创建后钩子' },
  { name: ':before-edge-remove', arg: 'BeforeEdgeRemoveEvent', return: 'boolean | Promise<boolean>', desc: '连线删除前钩子，返回 false 阻止删除' },
  { name: ':after-edge-remove', arg: 'AfterEdgeRemoveEvent', return: 'void', desc: '连线删除后钩子' },

  // ─── 数据生命周期钩子 ─────────────────────────────────────────────────────
  { name: ':after-data-loaded', arg: 'FlowData', return: 'void', desc: '数据加载完成后钩子' },
]
</script>

<style scoped>
