.ch-header__num { font-size: 12px; color: #1677ff; font-weight: 600; text-transform: uppercase; letter-spacing: 0.08em; }
.ch-header__title { font-size: 28px; font-weight: 700; color: #1a1a2e; margin: 8px 0 12px; }
.ch-header__desc { font-size: 15px; color: #666; line-height: 1.7; margin: 0; }
.ch-section { margin-bottom: 40px; }
.ch-section__title { font-size: 18px; font-weight: 600; color: #1a1a2e; margin: 0 0 16px; padding-bottom: 8px; border-bottom: 2px solid #f0f0f0; }
.ch-text { font-size: 14px; color: #444; line-height: 1.8; margin-bottom: 16px; }
.ch-text code, .ch-summary__item code { background: #f0f5ff; color: #1677ff; padding: 1px 5px; border-radius: 3px; font-size: 13px; }
.ch-callout { padding: 14px 16px; border-radius: 8px; font-size: 13px; line-height: 1.7; margin: 16px 0; }
