.ch-code-block__copy { font-size: 11px; background: none; border: 1px solid #d9d9d9; border-radius: 4px; padding: 2px 8px; cursor: pointer; color: #555; }
.ch-code-block__copy:hover { border-color: #1677ff; color: #1677ff; }
