export default "import type { CanvasConfig } from '../../../views/types/flow.types'\r\n\r\n/**\r\n * 默认画布配置\r\n * 对应 X6 Graph 初始化选项，所有字段均可通过 FlowDesignerLayout 的 canvasConfig prop 覆盖。\r\n * 参考：https://x6.antv.antgroup.com/api/graph/graph\r\n */\r\nexport const DEFAULT_CANVAS_CONFIG: CanvasConfig = {\r\n\r\n  // ─── 网格配置 ─────────────────────────────────────────────────────────────\r\n  // 对应 X6 Graph 选项：grid\r\n  // 参考：https://x6.antv.antgroup.com/api/graph/grid\r\n  grid: {\r\n    /** 是否显示网格。对应 grid.visible */\r\n    visible: true,\r\n    /**\r\n     * 网格类型。对应 grid.type\r\n     * - 'dot'  : 点状网格（默认）\r\n     * - 'mesh' : 线状网格\r\n     */\r\n    type: 'dot',\r\n    /** 网格单元尺寸（px），节点拖拽会按此值对齐（需开启 snapToGrid）。对应 grid.size */\r\n    size: 20,\r\n    /** 网格点/线的颜色。对应 grid.args[0].color */\r\n    color: '#6b6b6b',\r\n    /** 网格点/线的粗细（px）。对应 grid.args[0].thickness */\r\n    thickness: 2,\r\n  },\r\n\r\n  // ─── 对齐配置 ─────────────────────────────────────────────────────────────\r\n  // 对应 X6 插件：Snapline / graph.snapGrid\r\n  // 参考：https://x6.antv.antgroup.com/api/graph/snapline\r\n  align: {\r\n    /**\r\n     * 是否启用对齐线（Snapline）。\r\n     * 拖拽节点时显示辅助对齐线，帮助节点与其他节点对齐。\r\n     * 对应 Graph.use(Snapline, { enabled: true })\r\n     */\r\n    snaplineEnabled: true,\r\n    /**\r\n     * 是否将节点移动强制吸附到网格。\r\n     * true: 节点只能落在网格整数格点上；false: 自由移动。\r\n     * 对应 Graph 构造项 snapGrid: { size }\r\n     */\r\n    snapToGrid: false,\r\n    /**\r\n     * 对齐吸附半径（px）。\r\n     * 节点拖拽时，距对齐线/网格在此范围内时自动吸附。\r\n     * 对应 Snapline 插件的 tolerance 选项\r\n     */\r\n    snapRadius: 20,\r\n  },\r\n\r\n  // ─── 连线配置 ─────────────────────────────────────────────────────────────\r\n  // 对应 X6 Graph 构造项：connecting\r\n  // 参考：https://x6.antv.antgroup.com/api/graph/connecting\r\n  connection: {\r\n    /**\r\n     * 路由算法，决定连线走向。对应 connecting.router\r\n     * - 'manhattan' : 直角折线（自动绕障）\r\n     * - 'metro'     : 地铁风格直角折线\r\n     * - 'orth'      : 正交折线（不绕障）\r\n     */\r\n    router: 'metro',\r\n    /**\r\n     * 连接器类型，决定连线端点及弯角样式。对应 connecting.connector\r\n     * - 'rounded'  : 圆角折线\r\n     * - 'smooth'   : 平滑曲线（贝塞尔）\r\n     * - 'normal'   : 直线段无特殊处理\r\n     * - 'jumpover' : 交叉处绘制跳线弧（需 connector 支持）\r\n     * 注意：'jumpover' 是 X6 内置 connector 名称，用于连线交叉跳过效果\r\n     */\r\n    connector: 'rounded',\r\n    /**\r\n     * 是否允许连接到画布空白处（不连到任何节点/端口）。对应 connecting.allowBlank\r\n     * false: 连线必须连到有效节点，否则回弹取消\r\n     */\r\n    allowBlank: false,\r\n    /**\r\n     * 是否允许创建自环连线（起点和终点是同一节点）。对应 connecting.allowLoop\r\n     * false: 禁止节点自身连接自身\r\n     */\r\n    allowLoop: false,\r\n    /**\r\n     * 是否允许两个节点之间存在多条连线。对应 connecting.allowMulti\r\n     * false: 同一对节点只能有一条连线\r\n     */\r\n    allowMulti: false,\r\n    /** 连线描边宽度（px）。对应 edge 默认样式 attrs/line/strokeWidth */\r\n    strokeWidth: 2,\r\n    /** 连线描边颜色。对应 edge 默认样式 attrs/line/stroke（default 状态灰色） */\r\n    strokeColor: '#b0b8c4',\r\n    /**\r\n     * 连线交互层宽度（px）。\r\n     * 用于增大连线的 hover/click 判定范围，视觉上不可见。\r\n     * 对应 edge 默认样式 attrs/line/strokeWidth（用于交互检测）\r\n     * 推荐值：15-30，越大越容易触发 hover\r\n     */\r\n    interactionWidth: 20,\r\n    // 连线标签样式，在 GraphInitializer 中映射为 edge defaultLabel attrs\r\n    label: {\r\n      /** 标签背景色（SVG foreignObject 容器背景）*/\r\n      backgroundColor: '#ffffff',\r\n      /** 标签边框颜色（浅蓝色） */\r\n      borderColor: '#cccccc',\r\n      /** 标签边框宽度（px）*/\r\n      borderWidth: 1,\r\n      /** 标签文字颜色 */\r\n      textColor: '#999999',\r\n      /** 标签字号（px）*/\r\n      fontSize: 12,\r\n      /** 标签字重（CSS font-weight）*/\r\n      fontWeight: 500,\r\n      /**\r\n       * 标签在连线上的位置比例，取值范围 0～1。\r\n       * 0: 起点，0.5: 中点，1: 终点。对应 label.position.distance\r\n       */\r\n      position: 0.5,\r\n      /** 标签内边距（px），paddingX/paddingY 未设置时的 fallback */\r\n      padding: 4,\r\n      /** 左右内边距（px），优先级高于 padding */\r\n      paddingX: 6,\r\n      /** 上下内边距（px），优先级高于 padding。设置较小值以补偿 SVG text bbox 含字体行距 */\r\n      paddingY: 2,\r\n      /** 背景矩形垂直方向微调（px），正值向下，用于补偿 SVG text baseline 上下不对称（ascender > descender） */\r\n      offsetY: 1,\r\n      /** 标签背景圆角（px）*/\r\n      borderRadius: 4,\r\n      /**\r\n       * SVG 文字水平锚点。对应 label text-anchor 属性\r\n       * - 'start'  : 左对齐\r\n       * - 'middle' : 居中（默认）\r\n       * - 'end'    : 右对齐\r\n       */\r\n      textAnchor: 'middle',\r\n      /**\r\n       * SVG 文字垂直锚点。对应 label dominant-baseline 等效属性\r\n       * - 'top'    : 顶部对齐\r\n       * - 'middle' : 垂直居中（默认）\r\n       * - 'bottom' : 底部对齐\r\n       */\r\n      textVerticalAnchor: 'middle',\r\n      /**\r\n       * 标签鼠标事件穿透。对应 CSS pointer-events\r\n       * 'none': 标签不捕获鼠标事件，点击穿透到连线本身\r\n       */\r\n      pointerEvents: 'auto',\r\n    },\r\n  },\r\n\r\n  // ─── 交互配置 ─────────────────────────────────────────────────────────────\r\n  // 参考：https://x6.antv.antgroup.com/api/graph/panning\r\n  //       https://x6.antv.antgroup.com/api/graph/mousewheel\r\n  //       https://x6.antv.antgroup.com/api/graph/selection\r\n  interaction: {\r\n    /**\r\n     * 是否开启画布拖拽平移（按住空格或右键拖拽）。\r\n     * 对应 Graph 构造项 panning: { enabled: true }\r\n     */\r\n    panning: false,\r\n    /**\r\n     * 是否开启鼠标滚轮缩放画布。\r\n     * 对应 Graph 构造项 mousewheel: { enabled: true }\r\n     */\r\n    mousewheel: false,\r\n    /**\r\n     * 是否开启框选（Rubberband）。\r\n     * 鼠标在画布空白区域拖拽，绘制矩形框选中范围内的所有节点/边。\r\n     * 对应 Graph.use(Selection, { rubberband: true })\r\n     */\r\n    rubberband: true,\r\n    /**\r\n     * 是否允许多选（按住 Ctrl/Cmd 点击追加选中）。\r\n     * 对应 Selection 插件 multiple 选项\r\n     */\r\n    multipleSelection: true,\r\n    /**\r\n     * 是否允许拖拽移动节点。\r\n     * 对应 graph.options.interacting 中 nodeMovable 设为 true\r\n     */\r\n    movable: true,\r\n    /**\r\n     * 是否允许拖拽调整节点大小（显示 resize handle）。\r\n     * 对应 Graph.use(Transform, { resizing: { enabled: true } })\r\n     * 当前设为 false，节点尺寸固定\r\n     */\r\n    resizable: true,\r\n  },\r\n\r\n  // ─── 高亮配置 ─────────────────────────────────────────────────────────────\r\n  // 高亮效果通过 X6 高亮器（Highlighter）实现，在 GraphInitializer 中注册。\r\n  // 参考：https://x6.antv.antgroup.com/api/registry/highlighter\r\n  highlight: {\r\n    // 节点悬停高亮\r\n    nodeHover: {\r\n      /** 是否在节点悬停时高亮 */\r\n      enabled: false,\r\n      /** 高亮描边颜色 */\r\n      strokeColor: '#1677ff',\r\n      /** 高亮描边宽度（px）*/\r\n      strokeWidth: 2,\r\n      /** 是否附加阴影效果 */\r\n      shadow: true,\r\n    },\r\n    // 节点选中高亮（当前由各节点组件自身 CSS 处理，此项保留供扩展）\r\n    nodeSelected: {\r\n      /** 是否在节点选中时通过高亮器添加外框 */\r\n      enabled: false,\r\n      strokeColor: '#1677ff',\r\n      strokeWidth: 2.5,\r\n      shadow: true,\r\n    },\r\n    // 连线悬停高亮\r\n    edgeHover: {\r\n      /** 是否在连线悬停时高亮 */\r\n      enabled: true,\r\n      strokeColor: '#1677ff',\r\n      textColor: '#1677ff',\r\n      strokeWidth: 2,\r\n    },\r\n    // 连线悬停重叠优化（hover 时降低重叠连线的透明度，高密度连线场景提升可读性）\r\n    edgeHoverOverlap: {\r\n      /** 是否启用重叠连线透明度优化 */\r\n      enabled: true,\r\n      /** 重叠连线的目标透明度（0-1） */\r\n      opacity: 0.36,\r\n      /** 透明度过渡动画时长（ms） */\r\n      transitionDuration: 150,\r\n      /** 当连线数量超过此值时自动禁用该功能（性能保护），0 或 undefined 表示不限制 */\r\n      disableWhenEdgeCountExceeds: 100,\r\n    },\r\n    // 连线选中高亮（由 X6 Selection 插件自动触发）\r\n    edgeSelected: {\r\n      /** 是否在连线选中时高亮 */\r\n      enabled: true,\r\n      strokeColor: '#1677ff',\r\n      textColor: '#1677ff',\r\n      strokeWidth: 2,\r\n    },\r\n    // 端口默认样式（静止状态，节点注册时使用）\r\n    portDefault: {\r\n      /** 端口填充颜色 */\r\n      fill: '#ffffff',\r\n      /** 端口描边颜色 */\r\n      stroke: '#1677ff',\r\n      /** 端口圆半径（px）*/\r\n      size: 4,\r\n      /** 端口描边宽度（px）*/\r\n      strokeWidth: 2,\r\n    },\r\n    // 端口悬停高亮（鼠标悬停在端口上时）\r\n    portHover: {\r\n      /** 是否在端口悬停时高亮 */\r\n      enabled: true,\r\n      /** 端口高亮描边颜色 */\r\n      strokeColor: '#1677ff',\r\n      /** 端口高亮填充颜色 */\r\n      fillColor: '#1677ff',\r\n      /** 端口描边宽度 */\r\n      strokeWidth: 2,\r\n      /** 端口高亮时的圆半径（px）*/\r\n      size: 4,\r\n    },\r\n    // 磁铁吸附高亮（连线终点靠近端口、准备连接时）\r\n    magnetAdsorbed: {\r\n      /** 是否在磁铁吸附时高亮目标端口 */\r\n      enabled: true,\r\n      strokeColor: '#1677ff',\r\n      strokeWidth: 6,\r\n    },\r\n    // 可用磁铁高亮（开始绘制连线时，标记所有可连接的端口）\r\n    magnetAvailable: {\r\n      /** 是否高亮显示当前可连接的端口 */\r\n      enabled: true,\r\n      /** 可连接端口的高亮颜色（绿色表示可用） #ff4d4f*/\r\n      strokeColor: '#52c41a',\r\n      //fillColor: '#0000fc',\r\n      fillColor: '#0000fc',\r\n      strokeWidth: 2,\r\n    },\r\n    // 节点悉停时出线流动高亮\r\n    nodeHoverOutEdgeFlow: {\r\n      /** 是否开启：鼠标悉停节点时，出线变为蓝色流动线 */\r\n      enabled: true,\r\n      /** 流动线颜色 */\r\n      strokeColor: '#1677ff',\r\n      /** 流动线宽度（px）*/\r\n      strokeWidth: 2,\r\n      /** 流动动画周期（s），值越小流动越快 */\r\n      duration: 0.6,\r\n      /** 当节点数量超过此值时自动禁用该功能（性能保护），0 或 undefined 表示不限制 */\r\n      disableWhenNodeCountExceeds: 500,\r\n      /** 当单个节点的出线数量超过此值时不启用流动动画（性能保护），0 或 undefined 表示不限制 */\r\n      disableWhenOutEdgeCountExceeds: 10,\r\n    },\r\n  },\r\n\r\n  // ─── 背景配置 ─────────────────────────────────────────────────────────────\r\n  // 对应 X6 Graph 构造项：background\r\n  // 参考：https://x6.antv.antgroup.com/api/graph/background\r\n  background: {\r\n    /** 画布背景颜色。对应 background.color */\r\n    color: '#f5f5f5',\r\n    // image?   : 背景图片 URL，对应 background.image\r\n    // repeat?  : 背景图片平铺方式，'repeat' | 'no-repeat' | 'watermark'\r\n    // opacity? : 背景图片透明度，取值 0～1\r\n  },\r\n\r\n  // ─── 小地图配置 ────────────────────────────────────────────────────────────\r\n  // 对应 X6 插件：MiniMap\r\n  // 参考：https://x6.antv.antgroup.com/api/graph/minimap\r\n  minimap: {\r\n    /** 是否启用小地图。对应 MiniMap 插件 enabled */\r\n    enabled: true,\r\n    /** 小地图容器宽度（px）*/\r\n    width: 180,\r\n    /** 小地图容器高度（px）*/\r\n    height: 120,\r\n    /** 小地图内边距（px），防止内容紧贴边缘 */\r\n    padding: 10,\r\n  },\r\n\r\n  // ─── 历史记录（撤销/重做）配置 ────────────────────────────────────────────\r\n  // 对应 X6 插件：History\r\n  // 参考：https://x6.antv.antgroup.com/api/graph/history\r\n  history: {\r\n    /** 是否启用历史记录（撤销/重做）。对应 History 插件 enabled */\r\n    enabled: true,\r\n    /**\r\n     * 历史栈最大条数。超出后自动丢弃最旧的记录。\r\n     * 对应 History 插件 stackSize 选项\r\n     */\r\n    stackSize: 100,\r\n    /**\r\n     * 是否忽略节点/边「添加」操作，不计入历史。\r\n     * 对应 History 插件 ignoreAdd 选项\r\n     */\r\n    ignoreAdd: false,\r\n    /**\r\n     * 是否忽略节点/边「删除」操作，不计入历史。\r\n     * 对应 History 插件 ignoreRemove 选项\r\n     */\r\n    ignoreRemove: false,\r\n    /**\r\n     * 是否忽略节点/边「属性变更」操作，不计入历史。\r\n     * 对应 History 插件 ignoreChange 选项\r\n     * ⚠️ 必须为 false，由 beforeAddCommand 白名单精确控制入栈内容\r\n     * 若设为 true，连线端点(source/target)的 change 也会被屏蔽，导致 redo 后位置错误\r\n     */\r\n    ignoreChange: false,\r\n  },\r\n\r\n  // ─── Tooltip 配置 ─────────────────────────────────────────────────────────\r\n  // Tooltip 悬停提示样式配置\r\n  tooltip: {\r\n    /** 字体大小（px）*/\r\n    fontSize: 13,\r\n    /** 字体粗细 */\r\n    fontWeight: 'bold' as const,\r\n    /** 文字颜色 */\r\n    color: '#ffffff',\r\n    /** 背景颜色（带透明度的黑色）*/\r\n    backgroundColor: 'rgba(0, 0, 0, 0.75)',\r\n    /** 内边距 */\r\n    padding: '6px 12px',\r\n    /** 圆角（px）*/\r\n    borderRadius: 4,\r\n    /** 阴影 */\r\n    boxShadow: '0 2px 8px rgba(0, 0, 0, 0.25)',\r\n    /** 是否显示箭头 */\r\n    arrowEnabled: true,\r\n    /** 箭头颜色（与背景色一致）*/\r\n    arrowColor: 'rgba(0, 0, 0, 0.75)',\r\n    /** 箭头高度（px）*/\r\n    arrowSize: 8,\r\n    /** z-index 层级 */\r\n    zIndex: 9999,\r\n    /** 最大宽度（undefined 表示不限制）*/\r\n    maxWidth: undefined,\r\n    /** 文本换行方式（nowrap 保持单行）*/\r\n    whiteSpace: 'nowrap' as const,\r\n    /** 水平偏移量（px），正值向右，负值向左 */\r\n    offsetX: 0,\r\n    /** 垂直偏移量（px），正值向下，负值向上 */\r\n    offsetY: 0,\r\n  },\r\n}\r\n"