<template>
  <a-drawer
    :open="internalVisible"
    :width="isFullscreen ? '100%' : internalWidth"
    :class="{ 'code-drawer--fullscreen': isFullscreen }"
    placement="right"
    :closable="false"
    :bodyStyle="{ padding: 0, height: '100%', display: 'flex', flexDirection: 'column' }"
    @close="handleClose"
  >
    <!-- 自定义头部 -->
    <div class="code-drawer__header">
      <div class="code-drawer__header-left">
        <span class="code-drawer__title">{{ internalTitle }}</span>
        <span class="code-drawer__language-tag" :style="{ background: languageColor }">
          {{ displayLanguage }}
        </span>
      </div>
      <div class="code-drawer__header-actions">
        <!-- 搜索按钮 -->
        <a-tooltip title="搜索代码 (Ctrl+F)">
          <a-button
            type="text"
            size="small"
            @click="toggleSearch"
          >
            <template #icon>
              <SearchOutlined />
            </template>
          </a-button>
        </a-tooltip>

        <!-- 字体缩放按钮组 -->
        <a-tooltip title="缩小字体 (Ctrl+-)">
          <a-button
            type="text"
            size="small"
            @click="decreaseFontSize"
            :disabled="fontSize <= 10"
          >
            <template #icon>
              <MinusOutlined />
            </template>
          </a-button>
        </a-tooltip>

        <span class="code-drawer__font-size-label">{{ fontSize }}px</span>

        <a-tooltip title="增大字体 (Ctrl++)">
          <a-button
            type="text"
            size="small"
            @click="increaseFontSize"
            :disabled="fontSize >= 24"
          >
            <template #icon>
              <PlusOutlined />
            </template>
          </a-button>
        </a-tooltip>

        <a-divider type="vertical" style="margin: 0 4px;" />

        <!-- 折叠/展开按钮 -->
        <a-tooltip :title="isExpanded ? '折叠代码' : '展开代码'">
          <a-button
            type="text"
            size="small"
            @click="toggleExpand"
          >
            <template #icon>
              <component :is="isExpanded ? 'ShrinkOutlined' : 'ArrowsAltOutlined'" />
            </template>
          </a-button>
        </a-tooltip>

        <!-- 全屏按钮 -->
        <a-tooltip :title="isFullscreen ? '退出全屏' : '全屏查看'">
          <a-button
            type="text"
            size="small"
            @click="toggleFullscreen"
          >
            <template #icon>
              <component :is="isFullscreen ? 'FullscreenExitOutlined' : 'FullscreenOutlined'" />
            </template>
          </a-button>
        </a-tooltip>

        <!-- 复制按钮 -->
        <a-tooltip :title="copyTooltip">
          <a-button
            type="text"
            size="small"
            @click="handleCopy"
          >
            <template #icon>
              <component :is="copyStatus === 'success' ? 'CheckOutlined' : 'CopyOutlined'" />
            </template>
          </a-button>
        </a-tooltip>

        <!-- 关闭按钮 -->
        <a-tooltip title="关闭 (ESC)">
          <a-button
            type="text"
            size="small"
            @click="handleClose"
          >
            <template #icon>
              <CloseOutlined />
            </template>
          </a-button>
        </a-tooltip>
      </div>
    </div>

    <!-- 搜索栏 -->
    <div v-if="showSearch" class="code-drawer__search-bar">
      <a-input
        ref="searchInputRef"
        v-model:value="searchKeyword"
        placeholder="搜索代码..."
        size="small"
        @keyup.enter="searchNext"
        @keyup.esc="toggleSearch"
      >
        <template #prefix>
          <SearchOutlined />
        </template>
        <template #suffix>
          <span class="code-drawer__search-count">
            {{ searchMatches.length > 0 ? `${currentMatchIndex + 1}/${searchMatches.length}` : '0/0' }}
          </span>
        </template>
      </a-input>
      <a-button-group size="small">
        <a-button @click="searchPrev" :disabled="searchMatches.length === 0">
          <UpOutlined />
        </a-button>
        <a-button @click="searchNext" :disabled="searchMatches.length === 0">
          <DownOutlined />
        </a-button>
      </a-button-group>
    </div>

    <!-- 代码内容区 -->
    <div
      class="code-drawer__content"
      :class="{ 'code-drawer__content--collapsed': !isExpanded }"
    >
      <pre class="code-drawer__pre"><code
        ref="codeRef"
        class="code-drawer__code"
        :style="{
          fontSize: `${fontSize}px`,
          lineHeight: lineHeight
        }"
        v-html="highlightedCode"
      /></pre>
    </div>
  </a-drawer>
</template>

<script setup lang="ts">
import { ref, computed, watch, nextTick, onMounted, onBeforeUnmount } from 'vue'
import {
  SearchOutlined,
  CopyOutlined,
  CheckOutlined,
  CloseOutlined,
  FullscreenOutlined,
  FullscreenExitOutlined,
  ShrinkOutlined,
  ArrowsAltOutlined,
  UpOutlined,
  DownOutlined,
  PlusOutlined,
  MinusOutlined,
} from '@ant-design/icons-vue'

// ─── Props ──────────────────────────────────────────────────────────────────

interface Props {
  visible?: boolean
  code?: string
  language?: string
  title?: string
  width?: number | string
  showLineNumbers?: boolean
}

const props = withDefaults(defineProps<Props>(), {
  visible: false,
  code: '',
  language: 'text',
  title: '代码示例',
  width: 600,
  showLineNumbers: true,
})

// ─── Emits ──────────────────────────────────────────────────────────────────

const emit = defineEmits<{
  'update:visible': [value: boolean]
  'close': []
}>()

// ─── State ──────────────────────────────────────────────────────────────────

// 内部状态（支持 openDrawer 方法调用）
const internalVisible = ref(false)
const internalCode = ref('')
const internalLanguage = ref('text')
const internalTitle = ref('代码示例')
const internalWidth = ref<number | string>(600)

const isFullscreen = ref(false)
const isExpanded = ref(true)
const copyStatus = ref<'idle' | 'success' | 'error'>('idle')
const showSearch = ref(false)
const searchKeyword = ref('')
const searchMatches = ref<number[]>([])
const currentMatchIndex = ref(0)
const searchInputRef = ref()
const codeRef = ref<HTMLElement>()

// 字体大小控制（10-24px）
const fontSize = ref(13)
const MIN_FONT_SIZE = 10
const MAX_FONT_SIZE = 24

// 行间距控制（紧凑布局）
const lineHeight = ref(0.8)  // 从 1.8 缩小到 1.5

// ─── Computed ───────────────────────────────────────────────────────────────

/**
 * 当前使用的代码（优先使用内部状态，其次使用 props）
 */
const currentCode = computed(() => internalCode.value || props.code || '')

/**
 * 当前使用的语言（优先使用内部状态，其次使用 props）
 */
const currentLanguage = computed(() => internalLanguage.value || props.language || 'text')

// ─── Computed ───────────────────────────────────────────────────────────────

/**
 * 格式化后的代码
 */
const formattedCode = computed(() => {
  try {
    const lang = currentLanguage.value.toLowerCase()
    const code = currentCode.value

    // JSON 格式化
    if (lang === 'json') {
      const parsed = JSON.parse(code)
      return JSON.stringify(parsed, null, 2)
    }

    // 其他语言直接返回（可根据需要扩展）
    return code
  } catch {
    // 格式化失败则返回原始代码
    return currentCode.value
  }
})

/**
 * 带行号和语法高亮的代码
 */
const highlightedCode = computed(() => {
  const code = formattedCode.value
  const lines = code.split('\n')
  const maxLineNum = lines.length
  const padding = String(maxLineNum).length

  return lines
    .map((line, index) => {
      const lineNum = String(index + 1).padStart(padding, ' ')
      const highlightedLine = highlightSyntax(line, props.language)
      const searchHighlightedLine = highlightSearchMatches(highlightedLine, index)

      if (props.showLineNumbers) {
        return `<span class="code-line"><span class="line-number">${lineNum}</span><span class="line-content">${searchHighlightedLine}</span></span>`
      }
      return `<span class="code-line"><span class="line-content">${searchHighlightedLine}</span></span>`
    })
    .join('\n')
})

/**
 * 语言显示名称
 */
const displayLanguage = computed(() => {
  const langMap: Record<string, string> = {
    vue: 'Vue',
    typescript: 'TypeScript',
    ts: 'TypeScript',
    javascript: 'JavaScript',
    js: 'JavaScript',
    json: 'JSON',
    html: 'HTML',
    css: 'CSS',
    scss: 'SCSS',
    less: 'Less',
    text: 'Text',
  }
  return langMap[currentLanguage.value.toLowerCase()] || currentLanguage.value.toUpperCase()
})

/**
 * 语言标签颜色
 */
const languageColor = computed(() => {
  const colorMap: Record<string, string> = {
    vue: '#42b883',
    typescript: '#3178c6',
    ts: '#3178c6',
    javascript: '#f7df1e',
    js: '#f7df1e',
    json: '#292929',
    html: '#e34c26',
    css: '#264de4',
    scss: '#c6538c',
    less: '#1d365d',
  }
  return colorMap[currentLanguage.value.toLowerCase()] || '#999999'
})

/**
 * 复制按钮提示
 */
const copyTooltip = computed(() => {
  if (copyStatus.value === 'success') return '已复制'
  if (copyStatus.value === 'error') return '复制失败'
  return '复制代码'
})

// ─── Methods ────────────────────────────────────────────────────────────────

/**
 * 简单的语法高亮（根据语言类型）
 */
function highlightSyntax(line: string, language: string): string {
  const lang = language.toLowerCase()
  let highlighted = escapeHtml(line)

  if (lang === 'json') {
    // JSON 高亮：键、字符串、数字、布尔值、null
    highlighted = highlighted
      .replace(/"([^"]+)":/g, '<span class="hl-key">"$1"</span>:')
      .replace(/: "([^"]*)"/g, ': <span class="hl-string">"$1"</span>')
      .replace(/: (\d+\.?\d*)/g, ': <span class="hl-number">$1</span>')
      .replace(/: (true|false)/g, ': <span class="hl-boolean">$1</span>')
      .replace(/: (null)/g, ': <span class="hl-null">$1</span>')
  } else if (lang === 'vue' || lang === 'html') {
    // Vue/HTML 高亮：标签、属性
    highlighted = highlighted
      .replace(/(&lt;\/?)([\w-]+)/g, '$1<span class="hl-tag">$2</span>')
      .replace(/([\w-]+)=/g, '<span class="hl-attr">$1</span>=')
      .replace(/="([^"]*)"/g, '="<span class="hl-string">$1</span>"')
  } else if (lang === 'typescript' || lang === 'ts' || lang === 'javascript' || lang === 'js') {
    // JS/TS 高亮：关键字、字符串、注释
    highlighted = highlighted
      .replace(/\b(const|let|var|function|return|if|else|for|while|class|interface|type|import|export|from|default|async|await)\b/g, '<span class="hl-keyword">$1</span>')
      .replace(/'([^']*)'/g, "'<span class=\"hl-string\">$1</span>'")
      .replace(/"([^"]*)"/g, '"<span class="hl-string">$1</span>"')
      .replace(/\/\/(.*)/g, '<span class="hl-comment">//$1</span>')
  } else if (lang === 'css' || lang === 'scss' || lang === 'less') {
    // CSS 高亮：选择器、属性、值
    highlighted = highlighted
      .replace(/([.#]?[\w-]+)\s*\{/g, '<span class="hl-selector">$1</span> {')
      .replace(/([\w-]+):/g, '<span class="hl-attr">$1</span>:')
      .replace(/: ([^;]+);/g, ': <span class="hl-value">$1</span>;')
  }

  return highlighted
}

/**
 * 转义 HTML 特殊字符
 */
function escapeHtml(text: string): string {
  const map: Record<string, string> = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;',
  }
  return text.replace(/[&<>"']/g, m => map[m])
}

/**
 * 高亮搜索匹配项
 */
function highlightSearchMatches(line: string, lineIndex: number): string {
  if (!searchKeyword.value || searchMatches.value.length === 0) {
    return line
  }

  // 检查当前行是否包含匹配项
  const currentMatch = searchMatches.value[currentMatchIndex.value]
  const isCurrentLine = currentMatch === lineIndex

  const keyword = escapeHtml(searchKeyword.value)
  const regex = new RegExp(keyword, 'gi')

  return line.replace(regex, match => {
    const className = isCurrentLine ? 'search-match search-match--current' : 'search-match'
    return `<mark class="${className}">${match}</mark>`
  })
}

/**
 * 复制代码
 */
async function handleCopy() {
  try {
    await navigator.clipboard.writeText(formattedCode.value)
    copyStatus.value = 'success'
    setTimeout(() => {
      copyStatus.value = 'idle'
    }, 2000)
  } catch (err) {
    console.error('复制失败:', err)
    copyStatus.value = 'error'
    setTimeout(() => {
      copyStatus.value = 'idle'
    }, 2000)
  }
}

/**
 * 关闭 Drawer
 */
function handleClose() {
  // 直接关闭内部状态（适用于 openDrawer 方法调用）
  internalVisible.value = false

  // 同时通知父组件（适用于 v-model 方式，如果没有监听也不会报错）
  emit('update:visible', false)
  emit('close')

  // 重置状态
  isFullscreen.value = false
  showSearch.value = false
  searchKeyword.value = ''
  searchMatches.value = []
}

// ─── 公开方法 ────────────────────────────────────────────────────────────────

/**
 * 自动检测代码语言
 */
function detectLanguage(code: string): string {
  // 尝试解析 JSON
  try {
    JSON.parse(code)
    return 'json'
  } catch {
    // 不是有效的 JSON
  }

  // 检测 Vue 单文件组件
  if (code.includes('<template>') && code.includes('<script')) {
    return 'vue'
  }

  // 检测 HTML
  if (code.trim().startsWith('<!DOCTYPE') || code.trim().startsWith('<html')) {
    return 'html'
  }

  // 检测 CSS
  if (/^\s*[\w-]+\s*\{[\s\S]*\}\s*$/.test(code)) {
    return 'css'
  }

  // 检测 TypeScript (包含 interface、type 等关键字)
  if (/\b(interface|type|enum|namespace)\b/.test(code)) {
    return 'typescript'
  }

  // 检测 JavaScript (包含 const、let、var、function 等关键字)
  if (/\b(const|let|var|function|class|import|export)\b/.test(code)) {
    return 'javascript'
  }

  return 'text'
}

/**
 * 打开 Drawer（方法调用方式）
 * @param options 配置选项
 */
function openDrawer(options: {
  code: string
  language?: string
  title?: string
  width?: number | string
}) {
  internalCode.value = options.code

  // 如果没有指定语言，自动检测
  if (options.language) {
    internalLanguage.value = options.language
  } else {
    internalLanguage.value = detectLanguage(options.code)
    console.log('[CodeDrawer] 自动检测语言:', internalLanguage.value)
  }

  internalTitle.value = options.title || '代码示例'
  internalWidth.value = options.width || 600
  internalVisible.value = true
}

/**
 * 关闭 Drawer（方法调用方式）
 */
function closeDrawer() {
  internalVisible.value = false
  handleClose()
}

/**
 * 切换全屏
 */
function toggleFullscreen() {
  isFullscreen.value = !isFullscreen.value
}

/**
 * 切换展开/折叠
 */
function toggleExpand() {
  isExpanded.value = !isExpanded.value
}

/**
 * 增大字体
 */
function increaseFontSize() {
  if (fontSize.value < MAX_FONT_SIZE) {
    fontSize.value += 1
  }
}

/**
 * 缩小字体
 */
function decreaseFontSize() {
  if (fontSize.value > MIN_FONT_SIZE) {
    fontSize.value -= 1
  }
}

/**
 * 重置字体大小
 */
function resetFontSize() {
  fontSize.value = 13
}

/**
 * 处理键盘快捷键
 */
function handleKeydown(e: KeyboardEvent) {
  // Ctrl/Cmd + '+' / '=' 增大字体
  if ((e.ctrlKey || e.metaKey) && (e.key === '+' || e.key === '=')) {
    e.preventDefault()
    increaseFontSize()
  }

  // Ctrl/Cmd + '-' 缩小字体
  if ((e.ctrlKey || e.metaKey) && e.key === '-') {
    e.preventDefault()
    decreaseFontSize()
  }

  // Ctrl/Cmd + '0' 重置字体
  if ((e.ctrlKey || e.metaKey) && e.key === '0') {
    e.preventDefault()
    resetFontSize()
  }
}

/**
 * 切换搜索框
 */
function toggleSearch() {
  showSearch.value = !showSearch.value
  if (showSearch.value) {
    nextTick(() => {
      searchInputRef.value?.focus()
    })
  } else {
    searchKeyword.value = ''
    searchMatches.value = []
  }
}

/**
 * 执行搜索
 */
function performSearch() {
  if (!searchKeyword.value) {
    searchMatches.value = []
    return
  }

  const lines = formattedCode.value.split('\n')
  const matches: number[] = []

  lines.forEach((line, index) => {
    if (line.toLowerCase().includes(searchKeyword.value.toLowerCase())) {
      matches.push(index)
    }
  })

  searchMatches.value = matches
  currentMatchIndex.value = 0

  // 滚动到第一个匹配项
  if (matches.length > 0) {
    scrollToMatch(matches[0])
  }
}

/**
 * 搜索下一个
 */
function searchNext() {
  if (searchMatches.value.length === 0) return

  currentMatchIndex.value = (currentMatchIndex.value + 1) % searchMatches.value.length
  scrollToMatch(searchMatches.value[currentMatchIndex.value])
}

/**
 * 搜索上一个
 */
function searchPrev() {
  if (searchMatches.value.length === 0) return

  currentMatchIndex.value = currentMatchIndex.value === 0
    ? searchMatches.value.length - 1
    : currentMatchIndex.value - 1
  scrollToMatch(searchMatches.value[currentMatchIndex.value])
}

/**
 * 滚动到指定匹配项
 */
function scrollToMatch(lineIndex: number) {
  nextTick(() => {
    const codeElement = codeRef.value
    if (!codeElement) return

    const lines = codeElement.querySelectorAll('.code-line')
    const targetLine = lines[lineIndex] as HTMLElement
    if (targetLine) {
      targetLine.scrollIntoView({ behavior: 'smooth', block: 'center' })
    }
  })
}

// ─── Watchers ───────────────────────────────────────────────────────────────

watch(searchKeyword, () => {
  performSearch()
})

// 监听 props.visible 变化（v-model 方式）
watch(() => props.visible, (newVal) => {
  internalVisible.value = newVal || false

  if (!newVal) {
    // Drawer 关闭时重置状态
    isFullscreen.value = false
    isExpanded.value = true
    showSearch.value = false
    searchKeyword.value = ''
    searchMatches.value = []
    copyStatus.value = 'idle'
  }
})

// 监听 internalVisible 变化（方法调用方式）
watch(internalVisible, (newVal) => {
  if (newVal) {
    // Drawer 打开时添加键盘监听
    document.addEventListener('keydown', handleKeydown)
  } else {
    // Drawer 关闭时移除键盘监听
    document.removeEventListener('keydown', handleKeydown)

    // 重置内部状态
    isFullscreen.value = false
    isExpanded.value = true
    showSearch.value = false
    searchKeyword.value = ''
    searchMatches.value = []
    copyStatus.value = 'idle'
    fontSize.value = 13  // 重置字体大小

    // 延迟清空内部数据，确保关闭动画播放完成
    setTimeout(() => {
      internalCode.value = ''
      internalLanguage.value = 'text'
      internalTitle.value = '代码示例'
    }, 300)
  }
})

// ─── Lifecycle ──────────────────────────────────────────────────────────────

onBeforeUnmount(() => {
  // 组件卸载时移除键盘监听
  document.removeEventListener('keydown', handleKeydown)
})

// ─── 对外暴露 ────────────────────────────────────────────────────────────────

defineExpose({
  openDrawer,
  closeDrawer,
})
</script>

<style scoped>
/* ═══ Drawer 全屏样式 ═══ */
:deep(.code-drawer--fullscreen .ant-drawer-content-wrapper) {
  width: 100% !important;
}

/* ═══ 头部 ═══ */
.code-drawer__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 16px;
  background: #fff;
  border-bottom: 1px solid #f0f0f0;
  flex-shrink: 0;
}

.code-drawer__header-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

.code-drawer__title {
  font-size: 16px;
  font-weight: 500;
  color: #333;
}

.code-drawer__language-tag {
  padding: 2px 8px;
  font-size: 11px;
  color: #fff;
  border-radius: 3px;
  text-transform: uppercase;
  font-weight: 600;
  letter-spacing: 0.5px;
}

.code-drawer__header-actions {
  display: flex;
  gap: 4px;
  align-items: center;
}

.code-drawer__font-size-label {
  font-size: 11px;
  color: #666;
  font-weight: 500;
  user-select: none;
  min-width: 32px;
  text-align: center;
}

/* ═══ 搜索栏 ═══ */
.code-drawer__search-bar {
  display: flex;
  gap: 8px;
  padding: 8px 16px;
  background: #fafafa;
  border-bottom: 1px solid #f0f0f0;
  flex-shrink: 0;
}

.code-drawer__search-bar :deep(.ant-input-affix-wrapper) {
  flex: 1;
}

.code-drawer__search-count {
  font-size: 12px;
  color: #999;
  user-select: none;
  min-width: 40px;
  text-align: right;
}

/* ═══ 内容区 ═══ */
.code-drawer__content {
  flex: 1;
  overflow: auto;
  background: #fafafa;
}

.code-drawer__content--collapsed {
  max-height: 400px;
}

.code-drawer__pre {
  margin: 0;
  padding: 16px;
  background: #fafafa;
  overflow: visible;
}

.code-drawer__code {
  display: block;
  font-family: 'Consolas', 'Monaco', 'Courier New', monospace;
  /* font-size: 13px; */ /* 移除固定字体大小，改用动态绑定 */
  /* line-height: 1.8; */ /* 移除固定行间距，改用动态绑定（现在是 1.5） */
  color: #333;
  white-space: pre;
  word-wrap: normal;
  overflow-wrap: normal;
  transition: font-size 0.2s ease, line-height 0.2s ease;  /* 添加过渡动画 */
}

/* ═══ 代码行 ═══ */
:deep(.code-line) {
  display: block;
}

:deep(.line-number) {
  display: inline-block;
  width: 40px;
  margin-right: 16px;
  text-align: right;
